/*!
 * Minimaler HTMX-Ersatz: nur das, was das Dashboard braucht.
 * Unterstützt: hx-get + hx-trigger="every Ns" + hx-swap="innerHTML"
 * Plus: persistenter Open-State der Detail-Panels über sessionStorage.
 *
 * Wir bündeln HTMX nicht im Repo, damit das Hub-Bundle klein und offline-fähig
 * bleibt.
 */
(function () {
    "use strict";

    var STORAGE_KEY = "hotsport.openDetails";

    function getOpenIds() {
        try {
            return JSON.parse(sessionStorage.getItem(STORAGE_KEY) || "[]");
        } catch (e) {
            return [];
        }
    }

    function setOpenIds(ids) {
        try { sessionStorage.setItem(STORAGE_KEY, JSON.stringify(ids)); } catch (e) {}
    }

    // Die Buttons rufen `toggleDetail(id)` auf – siehe _pi_table.html
    window.toggleDetail = function (id) {
        var el = document.getElementById(id);
        if (!el) return;
        el.classList.toggle("open");
        var ids = getOpenIds();
        var idx = ids.indexOf(id);
        if (el.classList.contains("open")) {
            if (idx < 0) ids.push(id);
        } else if (idx >= 0) {
            ids.splice(idx, 1);
        }
        setOpenIds(ids);
    };

    function reapplyOpenState(root) {
        var ids = getOpenIds();
        ids.forEach(function (id) {
            var el = (root || document).querySelector("#" + CSS.escape(id));
            if (el) el.classList.add("open");
        });
    }

    function parseEvery(value) {
        if (!value) return null;
        var m = /^every\s+(\d+)(s|ms)$/.exec(value.trim());
        if (!m) return null;
        var n = parseInt(m[1], 10);
        return m[2] === "s" ? n * 1000 : n;
    }

    function refresh(el) {
        var url = el.getAttribute("hx-get");
        if (!url) return;
        fetch(url, { credentials: "same-origin" })
            .then(function (r) { return r.ok ? r.text() : ""; })
            .then(function (html) {
                if (!html) return;
                el.innerHTML = html;
                reapplyOpenState(el);
            })
            .catch(function () { /* offline – beim nächsten Tick erneut versuchen */ });
    }

    function init() {
        reapplyOpenState(document);
        var nodes = document.querySelectorAll("[hx-get][hx-trigger]");
        nodes.forEach(function (el) {
            var interval = parseEvery(el.getAttribute("hx-trigger"));
            if (!interval) return;
            setInterval(function () { refresh(el); }, interval);
        });
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", init);
    } else {
        init();
    }
})();
